proof_block:
// Establish proc_dom membership in both post states.  proc_dom is preserved
// (==~ pre.proc_dom()), and pre.proc_dom().contains(proc_ptr) by requires.
assert(pre_self_.proc_dom().contains(proc_ptr));
assert(post1_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post2_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post1_self_.proc_dom().contains(proc_ptr));
assert(post2_self_.proc_dom().contains(proc_ptr));

// Domains agree between post1 and post2 (closed under each spec fn).
assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
assert(post1_self_.container_dom() == post2_self_.container_dom());
assert(post1_self_.endpoint_dom() == post2_self_.endpoint_dom());
assert(post1_self_.thread_perms@.dom() =~= pre_self_.thread_dom().insert(r1));
assert(post2_self_.thread_perms@.dom() =~= pre_self_.thread_dom().insert(r2));

// Apply the quota uniqueness helper inside a guard so its precondition is
// available (the ensures-antecedent gives the relational facts).
let pre_owning = pre_self_.get_proc(proc_ptr).owning_container;
let pre_quota = pre_self_.get_container(pre_owning).quota;
let post1_owning = post1_self_.get_proc(proc_ptr).owning_container;
let post2_owning = post2_self_.get_proc(proc_ptr).owning_container;
let post1_quota = post1_self_.get_container(post1_owning).quota;
let post2_quota = post2_self_.get_container(post2_owning).quota;

if pre_quota.spec_subtract_mem_4k(post1_quota, 1)
    && pre_quota.spec_subtract_mem_4k(post2_quota, 1) {
    lemma_spec_subtract_mem_4k_functional(pre_quota, 1, post1_quota, post2_quota);
    assert(post1_quota =~= post2_quota);
}

// Force quantifier instantiation of the two `forall|p_ptr|` ensures (one per
// post-state) so their disjoint triggers line up on the same skolem witness.
assert forall|p_ptr: ProcPtr|
    post1_self_.proc_dom().contains(p_ptr) && p_ptr != proc_ptr
    implies #[trigger] post1_self_.get_proc(p_ptr)
        =~= post2_self_.get_proc(p_ptr) by {
    assert(post2_self_.proc_dom().contains(p_ptr));
    assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
};

// Same for the `forall|container_ptr|` ensures over owned_procs.
assert forall|c_ptr: ContainerPtr|
    post1_self_.container_dom().contains(c_ptr)
    && c_ptr != post1_self_.get_proc(proc_ptr).owning_container
    && c_ptr != post2_self_.get_proc(proc_ptr).owning_container
    implies #[trigger] post1_self_.get_container(c_ptr).owned_procs
        =~= post2_self_.get_container(c_ptr).owned_procs by {
    assert(post2_self_.container_dom().contains(c_ptr));
    assert(post1_self_.get_container(c_ptr).owned_procs
        =~= pre_self_.get_container(c_ptr).owned_procs);
    assert(post2_self_.get_container(c_ptr).owned_procs
        =~= pre_self_.get_container(c_ptr).owned_procs);
};

// Pcid / ioid for proc_ptr are pinned by both ensures to pre's values.
assert(post1_self_.get_proc(proc_ptr).pcid =~= post2_self_.get_proc(proc_ptr).pcid);
assert(post1_self_.get_proc(proc_ptr).ioid =~= post2_self_.get_proc(proc_ptr).ioid);

// Page closures agree (both insert(page_ptr) into pre.page_closure()).
assert(post1_self_.page_closure() =~= post2_self_.page_closure());
